#include <bits/stdc++.h>
using namespace std;

int n, q, m, ans;
int f[305], cnt[305];

void DFS(int x) {
    cnt[x]++;
    if (cnt[x] == m) ans = max(ans, x);
    if (f[x] != x) {
        DFS(f[x]);
    }
}

int main() {
    cin >> n;
    for (int i = 1; i < n; i++) {
        cin >> f[i];
    }
    cin >> q;
    while (q--) {
        memset(cnt, 0, sizeof(cnt));
        ans = 0;
        cin >> m;
        for (int i = 0; i < m; i++) {
            int x;
            cin >> x;
            DFS(x);
        }
        cout << ans << endl;
    }
    return 0;
}
